#include <functional>
#include <iostream>
int main() {
    int x = 5, y = 10;
    std::array<std::reference_wrapper<int>, 2> v {
        std::ref(x), std::ref(y)
    };
    for (int& val : v) {
        val += 3;
    }
    std::cout << x << ' ' << y << '\n';
