This code intends to create an array of references to `a`, `b`, and `c`, double each through the array, and then print the original variables. Find the bug.

```cpp
#include <array>
#include <functional>
#include <iostream>
int main() {
    int a = 2, b = 4, c = 6;
    std::array<std::reference_wrapper<int>, 3> refs { a, b, c };
    for (int v : refs) {   // note: int v, not int& v
        v *= 2;
    }
    std::cout << a << ' ' << b << ' ' << c << '\n';
    return 0;
}
```
